const [articles, setArticles] = useState([
  { id: 1, nom: 'Manioc', achete: false },
  { id: 2, nom: 'Poisson', achete: false },
  { id: 3, nom: 'Tomates', achete: false }
]);

const ajouterArticle = (nom) => {
  setArticles([...articles, { id: Date.now(), nom, achete: false }]);
};

const toggleAchete = (id) => {
  setArticles(articles.map(article =>
    article.id === id ? { ...article, achete: !article.achete } : article
  ));
};

const supprimerArticle = (id) => {
  setArticles(articles.filter(article => article.id !== id));
};

